// Obtém o telefone do JSON
const telefoneOriginal = $node["fluxo_chamado"].json["body"]["telefone"] || "";

// Verifica se o telefone está vazio
if (!telefoneOriginal) {
    return [{ json: { telefoneFormatado: "Telefone vazio" } }];
}

// Remove todos os caracteres não numéricos
const telefoneLimpo = telefoneOriginal.replace(/\D/g, "");

// Verifica se tem pelo menos 10 dígitos
if (telefoneLimpo.length < 10) {
    return [{ json: { telefoneFormatado: "Número inválido" } }];
}

// Verifica se o número começa com 55 (Brasil)
const isNacional = telefoneLimpo.startsWith("55");

// Se for internacional, retorna exatamente como veio
if (!isNacional) {
    return [{ json: { telefoneFormatado: telefoneLimpo } }];
}

// Se chegou até aqui, é do Brasil e precisa ser formatado
const telefoneSemDDI = telefoneLimpo.slice(2); // Remove o 55
const DDD = telefoneSemDDI.slice(0, 2);
let numero = telefoneSemDDI.slice(2);

// Se DDD <= 28 e número tem 8 dígitos, adiciona o 9
if (parseInt(DDD) <= 28 && numero.length === 8) {
    numero = "9" + numero;
}

// Se DDD > 28 e número tem 8 dígitos, também adiciona o 9
if (parseInt(DDD) > 28 && numero.length === 8) {
    numero = "9" + numero;
}

// Retorna o número formatado com DDI (55)
const telefoneFormatado = `55${DDD}${numero}`;

return [{ json: { telefoneFormatado } }];

// Obter o template do banco de dados
let template = $node["pesquisa_json_fields_deal2"].json["payload_fields"];

// Verifique se o template é uma string JSON ou já um objeto
if (typeof template === "string") {
  try {
    template = JSON.parse(template); // Converte a string JSON em um objeto
  } catch (error) {
    throw new Error("Erro ao converter template para JSON: " + error.message);
  }
}

// Obter os dados diretamente do "body" do webhook
const payload = $node["fluxo_chamado"].json["body"]["payload"]; // Acessa o body diretamente

// Função para sanitizar valores e substituir os placeholders no template
const replacePlaceholders = (template, data) => {
  const stringified = JSON.stringify(template); // Converte o template para string

  const replaced = stringified.replace(/{{\s*(\w+)\s*}}/g, (_, key) => {
    if (data[key] !== undefined) {
      // Sanitiza valores: remove caracteres problemáticos e escapa aspas
      return String(data[key])
        .replace(/[\r\n\t]/g, " ") // Remove quebras de linha e tabulações
        .replace(/"/g, '\\"'); // Escapa aspas duplas
    } else {
      console.warn(`Placeholder {{ ${key} }} não encontrado no payload.`);
      return ''; // Retorna vazio se o valor não existir
    }
  });

  try {
    return JSON.parse(replaced); // Converte de volta para JSON
  } catch (error) {
    throw new Error("Erro ao converter replaced para JSON: " + error.message);
  }
};

// Substituir os placeholders no template com os dados do webhook
const result = replacePlaceholders(template, payload);

// Retornar o resultado para o próximo node
return {
  custom_fields_values: result
};

